using BuildingBlocks.Charts;using BuildingBlocks.Grids;using Microsoft.EntityFrameworkCore;using Todos.Features;using Todos.Persistence;
namespace Todos.Charts;/** <summary>Todo chart datasource.</summary> */ public sealed class TodosChartDataSource(TodosDbContext db):IChartDataSource{/** <inheritdoc/> */ public string Key=>"todos";/** <inheritdoc/> */ public string DisplayName=>"المهام";/** <inheritdoc/> */ public ChartDataSourceMetadata Describe()=>new(Key,DisplayName,[new("status","الحالة",GridFieldType.Enum,true,false),new("priority","الأولوية",GridFieldType.Enum,true,false)]);/** <inheritdoc/> */ public async Task<ChartSeries> ComputeAsync(ChartComputeRequest r,CancellationToken ct){if(r.Aggregation!=ChartAggregation.Count)throw new ArgumentException("Todos supports Count only.",nameof(r));var q=db.Items.AsNoTracking().ApplyGridQuery(new GridQuery{Filters=r.Filters},TodoGrid.Fields);if(q.IsFailure)throw new ArgumentException(q.Error.Description,nameof(r));IReadOnlyList<ChartPoint> p=r.XField switch{"status"=>(await q.Value.GroupBy(x=>x.Status).Select(g=>new{g.Key,Count=g.Count()}).ToListAsync(ct)).Select(x=>new ChartPoint(x.Key.ToString(),x.Count)).ToArray(),"priority"=>(await q.Value.GroupBy(x=>x.Priority).Select(g=>new{g.Key,Count=g.Count()}).ToListAsync(ct)).Select(x=>new ChartPoint(x.Key.ToString(),x.Count)).ToArray(),_=>throw new ArgumentException("Unknown X field.",nameof(r))};return new(DisplayName,p);}}
